Loading data in SAS
/* Import data directly from URL using PROC HTTP */
filename rawdata temp;

proc http
  url="https://raw.githubusercontent.com/aftabsorwar/STAT-930-workshop/refs/heads/main/multivariate_workshop_dataset.csv"
  method="GET"
  out=rawdata;
run;

/* Read CSV into a SAS dataset */
proc import datafile=rawdata
  out=dat
  dbms=csv
  replace;
  getnames=yes;
run;

/* Save a local copy as CSV */
proc export data=dat
  outfile="multivariate_workshop_dataset.csv"
  dbms=csv
  replace;
run;

/* Quick look at structure */
proc contents data=dat;
run;

proc print data=dat(obs=6);
run;

Short description of the variable:
FieldID: Unique ID for each field.
Crop: Crop type grown (Corn / Soybean / Wheat).
Management: Practice type (Conventional vs CoverCrop).
SoilN: Soil nitrogen level (mg/kg). Higher often means more available nitrogen for plants.
SoilP: Soil phosphorus level (ppm). Supports root development and early growth.
OrgMatter: Organic matter (%). A soil health indicator. Improves fertility and water-holding capacity.
Moisture: Soil moisture (%). Amount of water in the soil.
NDVI: A satellite/drone-based vegetation index (0–1) that measures how green the crop is. Larger values generally mean more plant biomass and stronger vegetation cover.

PCA in SAS
/* Select only the numeric variables for PCA */
data X;
  set dat;
  keep SoilN SoilP OrgMatter Moisture NDVI;
run;

/* Check for missing values */
proc means data=X nmiss;
  var SoilN SoilP OrgMatter Moisture NDVI;
run;
/* Calculate and print the correlation matrix */
proc corr data=X;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "Correlation Matrix: Field Variables";
run;
/* Fit PCA using PROC PRINCOMP
   STD option standardizes variables (mean=0, sd=1)
   OUT= saves principal component scores */
proc princomp data=X std out=pca_scores;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "PCA of Field Variables";
run;

PC1 and PC2 are new summary variables created by PCA.They are made from your original variables, but they are designed to:
Summarize the data with fewer dimensions
Capture the biggest patterns in the data
a.PC1 captures the largest overall variation (the main trend).
b.PC2 captures the second-largest variation, separate from PC1.
these 2 are uncorrelated (i.e. PC2 is built so it does not repeat what PC1 already explains.)


/* Compute variance explained (eigenvalues) manually from PROC PRINCOMP output
   PROC PRINCOMP prints eigenvalues automatically.
   To get cumulative % explicitly, use PROC FACTOR with METHOD=PRIN */
proc factor data=X method=prin scree nfactors=5;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "Variance Explained by Each Principal Component";
run;

PC1 explains 55%, PC2 explains 22%. Together about 78% of the variation

/* Scree plot: variance explained per PC
   Use ODS Graphics with PROC PRINCOMP */
ods graphics on;
proc princomp data=X std plots=scree;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "Scree Plot of Principal Components";
run;
ods graphics off;
/* Show loadings (eigenvectors) for the first two PCs
   PROC PRINCOMP prints eigenvectors (loadings) by default */
proc princomp data=X std ncomp=2;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "Loadings for PC1 and PC2";
run;

A loading is a correlation-like weight, so its value is between −1 and +1What the size means
Close to +1 or −1 → strong contribution of that variable to the PC
Close to 0 → little contribution
The sign does not matter, magnitude matters.



For our example:
PC1 mainly represents a “soil fertility / soil health”.

Fields differ on PC1 mostly because of SoilN, SoilP, and organic matter.

PC2 mainly represents a “water + crop greenness”.

Fields differ on PC2 mostly because of soil moisture and NDVI.



/* Biplot: plot PC1 vs PC2 scores with variable vectors */
ods graphics on;
proc princomp data=X std ncomp=2 plots=pattern(vector ncomp=2);
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "Biplot: PC1 vs PC2";
run;
ods graphics off;

CA in SAS
/* Standardize variables to mean=0, sd=1 */
proc stdize data=X out=X_scaled method=std;
  var SoilN SoilP OrgMatter Moisture NDVI;
run;

/* Elbow method: run k-means for k = 1 to 8 and record within-cluster SS
   PROC FASTCLUS performs k-means clustering in SAS */
%macro elbow;
  %do k = 1 %to 8;
    proc fastclus data=X_scaled maxclusters=&k out=clus_&k outseed=seeds_&k
                  summary noprint;
      var SoilN SoilP OrgMatter Moisture NDVI;
    run;
  %end;
%mend elbow;
%elbow;
/* Plot within-cluster sum of squares for each k
   (Manually collect from PROC FASTCLUS summary output or use ODS OUTPUT) */
data wss_table;
  input k wss;
  datalines;
1 .
2 .
3 .
4 .
5 .
6 .
7 .
8 .
;
run;
/* Note: Replace the '.' values above with the within-cluster SS
   printed by PROC FASTCLUS for each k, then run the plot below. */

proc sgplot data=wss_table;
  series x=k y=wss / markers markerattrs=(symbol=circlefilled);
  xaxis label="Number of clusters (k)";
  yaxis label="Total within-cluster sum of squares";
  title "Elbow Plot for K-Means Clustering";
run;
/* Fit k-means with k=3 */
proc fastclus data=X_scaled maxclusters=3 out=clus_out seed=930;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "K-Means Clustering with k=3";
run;

/* Merge cluster labels back into original dataset */
data dat_clus;
  merge dat clus_out(keep=cluster rename=(cluster=Cluster));
run;

/* How many fields per cluster? */
proc freq data=dat_clus;
  tables Cluster;
  title "Observation Count per Cluster";
run;
/* Cluster means (interpretation table) */
proc means data=dat_clus mean;
  class Cluster;
  var SoilN SoilP OrgMatter Moisture NDVI;
  title "Cluster Means for Each Variable";
run;
/* PCA scores for plotting clusters in 2D space */
proc princomp data=X_scaled std ncomp=2 out=pca_plot_scores noprint;
  var SoilN SoilP OrgMatter Moisture NDVI;
run;

/* Merge PCA scores with cluster labels */
data pca_clusters;
  merge pca_plot_scores(keep=Prin1 Prin2) dat_clus(keep=Cluster);
run;

/* PCA scatter plot WITHOUT cluster coloring */
proc sgplot data=pca_clusters;
  scatter x=Prin1 y=Prin2;
  xaxis label="PC1";
  yaxis label="PC2";
  title "PCA Space (without cluster)";
run;

/* PCA scatter plot WITH cluster coloring */
proc sgplot data=pca_clusters;
  scatter x=Prin1 y=Prin2 / group=Cluster markerattrs=(symbol=circlefilled);
  xaxis label="PC1";
  yaxis label="PC2";
  title "Clusters shown in PCA Space";
run;

Points with the same color are grouped as similar field profiles. Separation means clusters differ.


Clustering helps us find field types without a response variable. Then we summarize each cluster using the mean soil and NDVI values to create an interpretable story.

PCA in SAS
Correlation Matrix
/* Correlation Heatmap */
ods graphics on;

proc corr data=iris nosimple noprob plots=matrix(histogram);
   var "Sepal.Length"n 
       "Sepal.Width"n 
       "Petal.Length"n 
       "Petal.Width"n;
run;

ods graphics off;




Petal.Length & Petal.Width = 0.9629 → extremely strong positive correlation
Sepal.Length strongly correlated with petal variables (≈ 0.82–0.87)
Sepal.Width negatively correlated with the others


PCA
/* PCA */
ods graphics on;

proc princomp data=iris
              out=iris_pca_scores
              outstat=iris_pca_stat
              std
              plots=scree;
   var "Sepal.Length"n "Sepal.Width"n "Petal.Length"n "Petal.Width"n;
run;

ods graphics off;




PC1 explains ~73% of total variation → very dominant.
PC1 + PC2 explain ~96% → two components are enough.
PC3 and PC4 contribute almost nothing.
So dimension can be reduced from 4 variables → 2 components safely.



For PC1:
Strong positive loadings for petal variables
Moderate positive loading for Sepal.Length
Negative for Sepal.Width
PC1 represents overall flower size (especially petal size).


For PC2:
Dominated by Sepal.Width
Almost no contribution from petal variables
PC2 represents sepal width variation independent of petal size.

Bi-plot
ods graphics on;
proc princomp data=iris plots=(patternplot score(ncomp=2));
    var "Sepal.Length"n "Sepal.Width"n "Petal.Length"n "Petal.Width"n;
    title "PCA – Biplot (Pattern + Score Plot)";
run;
ods graphics off;


proc sgplot data=iris_pca_scores;
   scatter x=prin1 y=prin2 / group=Species;
   xaxis label="PC1";
   yaxis label="PC2";
   title "PCA of Iris Data";
run;

CA in SAS
/* Standardize the numeric variables */
proc standard data=iris mean=0 std=1 out=iris_z;
   var "Sepal.Length"n "Sepal.Width"n "Petal.Length"n "Petal.Width"n;
run;

/* To see first 5 observation */
proc print data=iris_z(obs=5);
run;


We need to find optimum number of cluster to be considered for this analysis.

/* Elbow method (within-cluster variation) */
%macro elbow(maxk=6);

data elbow_results;
  length k 8 wcss 8;
  stop;
run;

%do k=1 %to &maxk;

   /* Run k-means and save per-observation distance to its cluster center */
   proc fastclus data=iris_z maxclusters=&k maxiter=100 out=clusout noprint;
      var "Sepal.Length"n "Sepal.Width"n "Petal.Length"n "Petal.Width"n;
   run;

   /* Compute WCSS = sum(distance^2) */
   data clusout2;
      set clusout;

      /* FASTCLUS usually creates DISTANCE. Some versions use _DIST_. */
      dist = coalesce(DISTANCE, _DIST_);
      dist2 = dist*dist;
   run;

   proc sql noprint;
      select sum(dist2) into :wcss from clusout2;
   quit;

   data temp;
      k = &k;
      wcss = &wcss;
   run;

   proc append base=elbow_results data=temp force;
   run;

%end;

%mend;

%elbow(maxk=6);


/* To see first 5 observation */
proc print data=clusout(obs=5);
run;


/* Elbow plot */
proc sgplot data=elbow_results;
   series x=k y=wcss / markers;
   xaxis label="Number of clusters (K)" integer;
   yaxis label="WCSS (sum of squared within-cluster distances)";
   title "Elbow Plot (Iris)";
run;


Proceed with the optimum cluster

/* Run K-means (K=3) */
proc fastclus data=iris_z maxclusters=3 maxiter=100 out=iris_k3;
   var "Sepal.Length"n "Sepal.Width"n "Petal.Length"n "Petal.Width"n;
run;

/* plotting the clusters */
proc princomp data=iris_z out=iris_pca std;
   var "Sepal.Length"n "Sepal.Width"n "Petal.Length"n "Petal.Width"n;
run;

/* Combine cluster labels with PCA scores */
data iris_pca_cluster;
   merge iris_pca iris_k3(keep=cluster);
run;

/* To see first 5 observation */
proc print data=iris_pca_cluster(obs=5);
run;

proc sgplot data=iris_pca_cluster;
   scatter x=prin1 y=prin2 / group=cluster;
   xaxis label="PC1";
   yaxis label="PC2";
   title "K-means Clusters on PCA Space";
run;

